/** Token amount returned by the SDK in human-readable decimal form. */
type EarnAssetAmount = Omit<AssetAmount, 'amount'> & {
    /** Token amount in human-readable decimal format. */
    readonly amount: string;
};
/**
 * Distributive `Omit` over a union.
 *
 * A plain `Omit<Union, K>` is not distributive: `keyof (A | B)` collapses to
 * the shared keys, dropping every variant-specific field and the discriminant
 * narrowing. Distributing over each member preserves the union.
 */
type DistributiveOmit<T, K extends PropertyKey> = T extends unknown ? Omit<T, K> : never;
/** Liquidity profile returned by the SDK with amounts as decimal strings. */
type EarnLiquidityProfile = Omit<LiquidityProfile, 'totalDeposits' | 'available' | 'totalSupply'> & {
    /** Total value deposited in human-readable decimal format. */
    readonly totalDeposits: string;
    /** Available liquidity in human-readable decimal format. */
    readonly available: string;
    /** Outstanding vault share tokens (ERC4626 totalSupply) in decimal format. */
    readonly totalSupply: string;
};
/**
 * Vault information returned by the SDK.
 *
 * Derived with a distributive `Omit` so each opportunity variant keeps its
 * product-specific fields and the `productType` discriminant.
 */
type EarnVaultInfo = DistributiveOmit<EarnOpportunity, 'totalDeposits' | 'liquidity' | 'liquidityProfile'> & {
    /** Total value deposited in human-readable decimal format. */
    readonly totalDeposits: string;
    /** Available liquidity in the vault in human-readable decimal format. */
    readonly liquidity: string;
    /**
     * Liquidity profile with amounts as human-readable decimal strings.
     *
     * Optional during the expand/contract migration window: a backend that
     * predates the nested facets omits it, so it is absent until the response
     * carries it.
     */
    readonly liquidityProfile?: EarnLiquidityProfile;
};
/** Result of a batch vault lookup. */
type EarnGetVaultsResult = Omit<GetVaultsResult, 'vaults'> & {
    /** Successfully resolved vault information. */
    readonly vaults: readonly EarnVaultInfo[];
};
/** Result of a vault discovery query. */
type EarnExploreVaultsResult = Omit<ExploreVaultsResult, 'vaults'> & {
    /** Vaults matching the query, in the requested sort order. */
    readonly vaults: readonly EarnVaultInfo[];
};
/** Accrued reward returned by the SDK in human-readable decimal form. */
type EarnAccruedRewardInfo = Omit<AccruedRewardInfo, 'amount'> & {
    /** Accrued reward amount in human-readable decimal format. */
    readonly amount: string;
};
type ProviderAvailablePositionPnLInfo = Extract<PositionPnLInfo, {
    readonly status: 'available';
}>;
/** Profit-and-loss calculation state returned by the SDK. */
type EarnPositionPnLInfo = (Omit<ProviderAvailablePositionPnLInfo, 'principalDeposited' | 'totalYieldEarned'> & {
    /** Total principal deposited minus withdrawals in human-readable decimal format. */
    readonly principalDeposited: string;
    /** Total yield earned in human-readable decimal format. */
    readonly totalYieldEarned: string;
}) | Exclude<PositionPnLInfo, ProviderAvailablePositionPnLInfo>;
/** Position information returned by the SDK. */
type EarnPositionInfo = Omit<PositionInfo, 'currentBalance' | 'shares' | 'pnl' | 'accruedRewards'> & {
    /** Current withdrawable value in human-readable decimal format. */
    readonly currentBalance: string;
    /** Vault shares held in human-readable decimal format. */
    readonly shares: string;
    /** Profit-and-loss calculation state and values for this position. */
    readonly pnl: EarnPositionPnLInfo;
    /** Pending reward tokens available for claiming. */
    readonly accruedRewards: readonly EarnAccruedRewardInfo[];
};
/** Kit-level reward amount returned from a claim rewards operation. */
type EarnClaimedAmount = Omit<ClaimedAmount, 'amount'> & {
    /** Reward amount in human-readable decimal format. */
    readonly amount: string;
};
/**
 * Kit-level result returned after claimable rewards are submitted on-chain.
 */
interface EarnClaimedRewardsResult {
    /** Discriminates the successful on-chain claim result. */
    readonly status: 'claimed';
    /** Reward token amounts that were claimed. */
    readonly rewards: readonly EarnClaimedAmount[];
    /** Confirmed on-chain transaction hash. */
    readonly txHash: string;
    /** Explorer URL for the confirmed on-chain transaction. */
    readonly explorerUrl: string;
}
/**
 * Kit-level result of a claim rewards operation.
 *
 * @example
 * ```typescript
 * const result: EarnClaimRewardsResult = await claimRewards(context, params)
 * if (result.status === 'no_rewards') {
 *   console.log('No rewards to claim')
 * } else {
 *   const reward = result.rewards[0]
 *   console.log(`Claimed ${reward?.amount} ${reward?.symbol}, tx: ${result.txHash}`)
 * }
 * ```
 */
type EarnClaimRewardsResult = NoClaimableRewardsResult | EarnClaimedRewardsResult;
/** Result of a deposit quote operation. */
type EarnDepositQuoteInfo = Omit<DepositQuoteInfo, 'deposit' | 'expectedShares' | 'fees' | 'gasFees'> & {
    /** Deposit asset and amount in human-readable decimal format. */
    readonly deposit: EarnAssetAmount;
    /** Expected vault shares to receive in human-readable decimal format. */
    readonly expectedShares: EarnAssetAmount;
    /** Fees applied to the deposit in human-readable decimal format. */
    readonly fees: readonly EarnAssetAmount[];
    /** Estimated native gas fees with amounts formatted as decimal strings. */
    readonly gasFees?: readonly EarnGasFeeEstimate[] | undefined;
};
/** Result of a withdrawal quote operation. */
type EarnWithdrawalQuoteInfo = Omit<WithdrawalQuoteInfo, 'withdrawal' | 'sharesToRedeem' | 'maxWithdrawable' | 'fees' | 'gasFees'> & {
    /** The withdrawal amount being quoted in human-readable decimal format. */
    readonly withdrawal: EarnAssetAmount;
    /** Vault shares that would be redeemed in human-readable decimal format. */
    readonly sharesToRedeem: EarnAssetAmount;
    /** Maximum amount the user can currently withdraw in human-readable decimal format. */
    readonly maxWithdrawable: EarnAssetAmount;
    /** Fees applied to the withdrawal in human-readable decimal format. */
    readonly fees: readonly EarnAssetAmount[];
    /** Estimated native gas fees with amounts formatted as decimal strings. */
    readonly gasFees?: readonly EarnGasFeeEstimate[] | undefined;
};
/** Result of a claim rewards quote operation. */
type EarnClaimRewardsQuoteInfo = Omit<ClaimRewardsQuoteInfo, 'rewards'> & {
    /** Reward tokens available for claiming in human-readable decimal format. */
    readonly rewards: readonly EarnAssetAmount[];
};
/**
 * Parameters for all EarnKit operations.
 *
 * @example
 * ```typescript
 * import type { EarnOperationParams } from '@circle-fin/earn-kit'
 *
 * function queueEarnOperation(params: EarnOperationParams) {
 *   return params
 * }
 * ```
 */
type EarnOperationParams = AnyDepositParams | WithdrawParams | ClaimRewardsParams | GetVaultsParams | ExploreVaultsParams | ExploreVaultsIteratorParams | GetPositionParams | GetDepositQuoteParams | GetWithdrawalQuoteParams | GetClaimRewardsQuoteParams;

/**
 * Parameters for initiating a cross-chain USDC bridge transfer.
 *
 * This type is used as the primary input to {@link BridgeKit.bridge}, allowing users to specify
 * the source and destination adapters, transfer amount, and optional configuration.
 *
 * - The `from` field specifies the source adapter context (wallet and chain).
 * - The `to` field specifies the destination, supporting both explicit and derived recipient addresses.
 * - The `config` field allows customization of bridge behavior (e.g., transfer speed).
 * - The `token` field is optional and defaults to 'USDC'; other tokens are not currently supported.
 *
 * @typeParam TFromAdapterCapabilities - The source adapter capabilities type.
 * @typeParam TToAdapterCapabilities - The destination adapter capabilities type.
 *
 * @example
 * ```typescript
 * import { BridgeKit, BridgeChain } from '@circle-fin/bridge-kit'
 *
 * const kit = new BridgeKit()
 *
 * // Using BridgeChain enum values (full autocomplete support)
 * const params: BridgeParams = {
 *   from: { adapter: sourceAdapter, chain: BridgeChain.Ethereum },
 *   to: { adapter: destAdapter, chain: BridgeChain.Base },
 *   amount: '10.5',
 *   config: { transferSpeed: 'FAST' },
 *   token: 'USDC'
 * }
 *
 * // Using string literals (also works with autocomplete)
 * const params2: BridgeParams = {
 *   from: { adapter: sourceAdapter, chain: 'Ethereum_Sepolia' },
 *   to: { adapter: destAdapter, chain: 'Base_Sepolia' },
 *   amount: '10.5'
 * }
 *
 * // With explicit recipient address:
 * const paramsWithAddress: BridgeParams = {
 *   from: { adapter: sourceAdapter, chain: BridgeChain.Ethereum },
 *   to: {
 *     recipientAddress: '0x742d35Cc6634C0532925a3b844Bc454e4438f44e',
 *     adapter: destAdapter,
 *     chain: BridgeChain.Base
 *   },
 *   amount: '10.5'
 * }
 *
 * // ❌ Compile error - Algorand is not a supported bridge chain
 * const invalidParams: BridgeParams = {
 *   from: { adapter: sourceAdapter, chain: 'Algorand' }, // TypeScript error!
 *   to: { adapter: destAdapter, chain: 'Base' },
 *   amount: '10.5'
 * }
 * ```
 *
 * @see {@link BridgeChain} for the enum of supported chains.
 * @see {@link BridgeChainIdentifier} for the type of valid chain values.
 */
interface BridgeParams<TFromAdapterCapabilities extends AdapterCapabilities = AdapterCapabilities, TToAdapterCapabilities extends AdapterCapabilities = AdapterCapabilities> {
    /**
     * The source adapter context (wallet and chain) for the transfer.
     */
    from: AdapterContext<TFromAdapterCapabilities, BridgeChainIdentifier>;
    /**
     * The destination for the transfer, supporting explicit or derived recipient addresses
     */
    to: BridgeDestination<TToAdapterCapabilities, BridgeChainIdentifier>;
    /**
     * The amount to transfer
     */
    amount: string;
    /**
     * Optional bridge configuration (e.g., transfer speed).
     * If omitted, defaults will be used
     */
    config?: BridgeConfig;
    /**
     * The token to transfer. Defaults to 'USDC'.
     * If omitted, the provider will use 'USDC' by default.
     */
    token?: 'USDC';
    /**
     * Optional invocation metadata for tracing and correlation.
     *
     * When provided, the `traceId` is used to correlate all events emitted during
     * the bridge operation. If not provided, an OpenTelemetry-compatible traceId
     * will be auto-generated.
     *
     * @example
     * ```typescript
     * const params: BridgeParams = {
     *   from: { adapter: sourceAdapter, chain: 'Ethereum' },
     *   to: { adapter: destAdapter, chain: 'Base' },
     *   amount: '100',
     *   invocationMeta: {
     *     traceId: 'my-custom-trace-id',
     *     callers: [{ type: 'app', name: 'MyDApp', version: '1.0.0' }],
     *   },
     * }
     * ```
     */
    invocationMeta?: InvocationMeta;
}

/**
 * Adapter context constrained to swap-supported chains.
 */
type SwapAdapterContext<TAdapterCapabilities extends AdapterCapabilities = AdapterCapabilities> = Omit<AdapterContext<TAdapterCapabilities>, 'chain'> & {
    chain: SwapChainIdentifier;
};
/**
 * Destination details for same-chain or cross-chain swaps.
 */
interface SwapDestination {
    /**
     * Optional destination chain.
     *
     * Defaults to `from.chain` for same-chain swaps.
     */
    chain?: SwapChainIdentifier;
    /**
     * Optional recipient address.
     *
     * Defaults to the source wallet address for same-chain swaps. Cross-chain
     * swaps require this field because the destination wallet may be on a
     * different chain/address format.
     */
    recipientAddress?: string;
}
/**
 * Allowance strategy for token approvals during swap operations.
 *
 * Defines how token allowances should be granted to the swap contract:
 * - `permit`: Use EIP-2612 permit signature (gas-efficient, no approval transaction)
 * - `approve`: Traditional approval transaction
 *
 * The default strategy is `permit` with fallback to `approve` if permit is not supported.
 */
type AllowanceStrategy = 'permit' | 'approve';
/**
 * Configuration options for swap operations.
 *
 * Controls swap behavior including allowance strategy, slippage tolerance,
 * minimum output amounts, custom fees, and kit identification.
 *
 * @example
 * ```typescript
 * // With percentage-based custom fee
 * const config: SwapConfig = {
 *   allowanceStrategy: 'permit',
 *   slippageBps: 300, // 3%
 *   stopLimit: '0.95', // Minimum 0.95 USDC output
 *   customFee: {
 *     percentageBps: 1000,  // 10% fee (100 bps = 1%)
 *     recipientAddress: '0x742d35Cc6634C0532925a3b844Bc454e4438f44e'
 *   }
 * }
 * ```
 *
 * @example
 * ```typescript
 * // Without custom fee
 * const config: SwapConfig = {
 *   slippageBps: 300,
 *   allowanceStrategy: 'approve'
 * }
 * ```
 */
interface SwapConfig {
    /**
     * Strategy for granting token allowances to the swap contract.
     *
     * Defaults to 'permit' with fallback to 'approve'.
     */
    allowanceStrategy?: AllowanceStrategy;
    /**
     * Maximum acceptable slippage in basis points (BPS).
     *
     * 1 BPS = 0.01%, so 300 BPS = 3% slippage.
     * Defaults to 300 BPS (3%).
     */
    slippageBps?: number;
    /**
     * Minimum acceptable output amount in human-readable format (stop-limit).
     *
     * If the estimated output falls below this value, the swap will fail.
     * Expressed as a decimal string (e.g., '0.4' for 0.4 USDT).
     * The value is automatically converted to base units using the tokenOut decimals.
     *
     * @example '99.5' for minimum 99.5 USDT output
     */
    stopLimit?: string;
    /**
     * Custom fee configuration for this swap (percentage-based approach).
     *
     * Allows specifying a percentage fee and recipient address at the
     * transaction level. This is mutually exclusive with kit-level callback
     * fee policy. If both are set, transaction-level takes precedence.
     *
     * For complex fee logic (VIP tiers, database lookups), use kit-level
     * callback approach via `setCustomFeePolicy()` instead.
     *
     * @remarks
     * - Service calculates fee using `estimatedAmount` for same-chain output fees
     * - Cross-chain fees are always collected from the source-chain input token
     * - Fee is sent to your configured `recipientAddress`
     * - Single API call (efficient)
     * - Must be greater than 0 and less than or equal to 10000 bps (100%)
     *
     * @example
     * ```typescript
     * customFee: {
     *   percentageBps: 1000,  // 10% fee
     *   recipientAddress: '0x742d35Cc6634C0532925a3b844Bc454e4438f44e'
     * }
     * ```
     */
    customFee?: {
        /**
         * Fee percentage in basis points.
         *
         * 100 bps = 1%, 1000 bps = 10%, 10000 bps = 100%
         *
         * Fee is calculated from `estimatedAmount` for same-chain output fees and
         * from the input amount for cross-chain swaps.
         * Must be greater than 0 and less than or equal to 10000 (maximum 100%).
         *
         * For complex fee logic, use kit-level `setCustomFeePolicy()` instead.
         *
         * @example 1000 // 10% fee
         */
        percentageBps: number;
        /**
         * Address that will receive the developer's 90% fee share.
         *
         * Must be valid on the fee payout chain: source chain for input-side fees
         * and cross-chain swaps, destination chain for same-chain output-side fees.
         *
         * @example '0x742d35Cc6634C0532925a3b844Bc454e4438f44e'
         */
        recipientAddress: string;
    };
    /**
     * Stablecoin Service Kit Key used to authenticate service-backed swap
     * requests.
     *
     * Treat this value as a credential. Do not log it, embed it in client-side
     * source, or expose it in telemetry.
     */
    kitKey?: string;
}
interface SwapParams<TFromAdapterCapabilities extends AdapterCapabilities = AdapterCapabilities> {
    /**
     * The source adapter context (wallet and chain) for the swap.
     */
    from: SwapAdapterContext<TFromAdapterCapabilities>;
    /**
     * The input token to swap from.
     *
     * Supports stablecoins (USDC, USDT, EURC, USDe, DAI, PYUSD),
     * wrapped tokens (WBTC, WETH, WSOL, WAVAX, WPOL),
     * and native tokens (NATIVE or chain-specific symbols).
     */
    tokenIn: SupportedSwapToken;
    /**
     * The output token to swap to.
     *
     * Supports stablecoins (USDC, USDT, EURC, USDe, DAI, PYUSD),
     * wrapped tokens (WBTC, WETH, WSOL, WAVAX, WPOL),
     * and native tokens (NATIVE or chain-specific symbols).
     */
    tokenOut: SupportedSwapToken;
    /**
     * The amount of the input token to swap.
     *
     * Expressed as a human-readable decimal string in token units
     * (e.g., `'0.05'` for 0.05 USDC or 0.05 ETH).
     */
    amountIn: string;
    /**
     * Optional destination chain/address.
     *
     * For same-chain swaps this may be omitted and the source wallet address is
     * used as the recipient. Cross-chain swaps require `recipientAddress`.
     */
    to?: SwapDestination;
    /**
     * Optional configuration for swap behavior.
     *
     * If omitted, defaults will be used:
     * - allowanceStrategy: 'permit' (fallback to 'approve')
     * - slippageBps: 300 (3%)
     */
    config?: SwapConfig;
}

/**
 * Operation types that support the `getFee`/`getFeeRecipient` hooks.
 */
type FeeOperationType = 'bridge' | 'swap';
/**
 * Maps operation types to their corresponding parameter interfaces.
 *
 * This interface maps operation types to their parameter structures for
 * compile-time validation in shared AppKit helpers.
 *
 * @remarks `earn` is included so consumers can refer to the full EarnKit
 * operation-parameter union through AppKit types. Developer fee hooks
 * intentionally use {@link FeeOperationType}, so they do not accept earn
 * parameters until EarnKit supports fee-bearing requests.
 *
 * @example
 * ```typescript
 * // TypeScript will enforce that bridge operations use BridgeParams
 * type BridgeParamsType = OperationParamsMap['bridge'] // BridgeParams
 * // TypeScript will enforce that swap operations use SwapParams
 * type SwapParamsType = OperationParamsMap['swap'] // SwapParams
 * // TypeScript will enforce that earn operations use EarnOperationParams
 * type EarnParamsType = OperationParamsMap['earn'] // EarnOperationParams
 * ```
 */
interface OperationParamsMap {
    bridge: BridgeParams;
    swap: SwapParams;
    earn: EarnOperationParams;
}
/**
 * Context interface for the AppKit with strongly typed getFee method.
 *
 * This interface uses TypeScript function overloads to provide type-safe
 * parameter validation based on the operation type. Each operation type
 * maps to specific parameter types, ensuring compile-time safety and
 * excellent developer experience with full IntelliSense support.
 *
 * The interface supports both direct operation-specific overloads and a
 * generic overload for advanced use cases while maintaining type safety.
 *
 * @example
 * ```typescript
 * // Bridge operation - uses BridgeParams
 * const bridgeFee = await context.getFee('bridge', {
 *   from: { adapter: sourceAdapter, chain: 'Ethereum' },
 *   to: { adapter: destAdapter, chain: 'Polygon' },
 *   amount: '100.50'
 * })
 * ```
 */
interface AppKitContext {
    /**
     * Get fee estimation for bridge or swap operations.
     *
     * Calculate the estimated fees for cross-chain bridge transfers, same-chain
     * token swaps. Returns the fee amount in smallest token units.
     *
     * The function signature uses TypeScript's generic constraint pattern to ensure
     * type safety: when type is 'bridge', params must be BridgeParams; when type
     * is 'swap', params must be SwapParams.
     *
     * @typeParam T - The fee operation type ('bridge' | 'swap')
     * @param type - Operation type: 'bridge' for cross-chain transfers, 'swap' for same-chain swaps
     * @param params - Operation-specific parameters matching the type
     * @returns Promise resolving to fee amount as string in smallest token units
     * @throws {@link ValidationError} If operation parameters are invalid
     * @throws {@link UnsupportedRouteError} If the operation route is not supported
     *
     * @example
     * ```typescript
     * // Bridge fee
     * const bridgeFee = await context.getFee?.('bridge', bridgeParams)
     *
     * // Swap fee
     * const swapFee = await context.getFee?.('swap', swapParams)
     *
     * // Generic usage
     * function estimateFee<T extends FeeOperationType>(
     *   operation: T,
     *   params: OperationParamsMap[T]
     * ) {
     *   return context.getFee(operation, params) // Fully type-safe
     * }
     * ```
     */
    getFee?<T extends FeeOperationType>(type: T, params: OperationParamsMap[T]): Promise<string>;
    /**
     * Get the fee recipient address for a specific operation and chain.
     *
     * This method returns the address that will receive protocol fees for
     * the specified operation type on the given chain. Useful for transparency
     * and fee tracking purposes.
     *
     * @remarks When this hook is used for bridging operations, the `params` object within `info` will be empty.
     * This is due to a limitation in the underlying `BridgeKit`, which does not provide bridge parameters
     * to its fee recipient hook.
     *
     * @typeParam T - The fee operation type ('bridge' | 'swap')
     * @param type - The specific operation type
     * @param info - Object containing chain and parameter information
     * @returns Promise resolving to the fee recipient address
     * @throws {@link ValidationError} If parameters are invalid
     * @throws {@link UnsupportedChainError} If the chain is not supported
     *
     * @example
     * ```typescript
     * const recipient = await context.getFeeRecipient('bridge', {
     *   chain: ethereumChain,
     *   params: bridgeParams
     * })
     * ```
     */
    getFeeRecipient?<T extends FeeOperationType>(type: T, info: {
        chain: ChainDefinition;
        params: OperationParamsMap[T];
    }): Promise<string>;
    /**
     * Event handlers registered for AppKit operations.
     *
     * This property stores event handlers that are registered via the AppKit's
     * `on()` method. Handlers are grouped by operation type. The runtime buckets
     * are `bridge` and `earn`; the context can add more operation buckets as
     * AppKit wires action handlers for additional kits.
     *
     * Within each operation bucket, handlers are keyed by action name (for
     * example, `bridge.approve` or `earn.deposit`) or `*` for wildcard handlers.
     * Each action can have multiple handlers registered, allowing multiple
     * subscribers to listen to the same event.
     *
     * The handlers are stored in the context to allow deferred registration with
     * underlying operation kits, enabling a clean separation between event
     * registration and operation execution.
     *
     * @example
     * ```typescript
     * const context = createContext()
     * // Handlers registered via kit.on() are stored by operation type
     * // Bridge handlers are registered with BridgeKit when bridge() runs
     * // Earn handlers are registered with EarnKit when earn operations run
     * ```
     */
    actions: Record<'bridge' | 'earn', Record<string, ((payload: unknown) => void)[]>>;
    /**
     * Disable error telemetry for all sub-kits.
     *
     * When `true`, none of the underlying kits (BridgeKit, SwapKit,
     * UnifiedBalanceKit) will POST error details to the telemetry
     * endpoint when operations throw. Defaults to `false` (enabled).
     *
     * @defaultValue false
     */
    disableErrorReporting?: boolean;
    /**
     * Custom HTTP headers forwarded with the underlying CCTP provider's
     * attestation (Iris) API requests made by bridge operations.
     *
     * @remarks
     * Headers are merged on top of the SDK defaults (such as `Content-Type`)
     * rather than replacing them. The header is forwarded as-is to Circle's API;
     * the SDK does not interpret it.
     */
    headers?: Record<string, string>;
}

